import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

// Each test names the concrete bug it would catch and asserts an exact,
// hand-computed expected value derived from the documented contract.

describe("mergeIntervals — empty and trivial inputs", () => {
  it("returns [] for empty input", () => {
    // Catches: a broken base case that returns undefined/null or a seeded interval.
    expect(mergeIntervals([])).toEqual([]);
  });

  it("returns a single interval unchanged", () => {
    // Catches: spurious merging/dropping when there is nothing to merge.
    expect(mergeIntervals([[1, 5]])).toEqual([[1, 5]]);
  });
});

describe("mergeIntervals — overlap merging", () => {
  it("merges two overlapping intervals into one", () => {
    // Catches: failing to combine [1,4] and [3,6] whose ranges overlap.
    expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
  });

  it("keeps the larger end when a later interval is fully contained", () => {
    // Catches: last[1] = end (instead of Math.max) shrinking [1,10] to [1,5].
    expect(mergeIntervals([[1, 10], [2, 5]])).toEqual([[1, 10]]);
  });

  it("chains three overlapping intervals into one", () => {
    // Catches: only merging adjacent pairs, not transitively across a run.
    expect(mergeIntervals([[1, 3], [2, 6], [5, 8]])).toEqual([[1, 8]]);
  });
});

describe("mergeIntervals — touching boundary (the merge threshold)", () => {
  it("merges intervals that touch at a shared endpoint", () => {
    // Boundary at: later.start === earlier.end. [1,2],[2,3] -> [1,3].
    // Catches: using `<` instead of `<=` so touching intervals stay split.
    expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
  });

  it("keeps intervals separate when there is a unit gap (just past touching)", () => {
    // Just above the threshold: earlier.end=2, later.start=3 -> gap of 1.
    // Catches: using `<=`+1 slack that wrongly fuses adjacent-but-disjoint ranges.
    expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
  });
});

describe("mergeIntervals — disjoint intervals", () => {
  it("keeps clearly separate intervals in ascending order", () => {
    // Catches: over-eager merging of ranges with a real gap between them.
    expect(mergeIntervals([[1, 2], [5, 6], [10, 12]])).toEqual([
      [1, 2],
      [5, 6],
      [10, 12],
    ]);
  });
});

describe("mergeIntervals — sorting", () => {
  it("sorts the output by start ascending regardless of input order", () => {
    // Catches: assuming input is pre-sorted; unsorted input would mis-merge.
    expect(mergeIntervals([[10, 12], [1, 2], [5, 6]])).toEqual([
      [1, 2],
      [5, 6],
      [10, 12],
    ]);
  });

  it("merges overlapping intervals presented out of order", () => {
    // Catches: comparing against the previous *input* rather than sorted order.
    expect(mergeIntervals([[3, 6], [1, 4]])).toEqual([[1, 6]]);
  });
});

describe("mergeIntervals — duplicates and degenerate points", () => {
  it("collapses identical intervals into one", () => {
    // Catches: emitting a duplicate instead of merging equal ranges.
    expect(mergeIntervals([[2, 4], [2, 4]])).toEqual([[2, 4]]);
  });

  it("merges a zero-width interval that touches another", () => {
    // start === end is allowed (start <= end). [5,5] touches [5,7] -> [5,7].
    // Catches: point intervals being dropped or left separate.
    expect(mergeIntervals([[5, 5], [5, 7]])).toEqual([[5, 7]]);
  });

  it("keeps a zero-width interval separate when it does not touch", () => {
    // Catches: point intervals being silently swallowed into a neighbor.
    expect(mergeIntervals([[1, 1], [3, 4]])).toEqual([[1, 1], [3, 4]]);
  });
});

describe("mergeIntervals — negative and mixed ranges", () => {
  it("merges across zero with negative starts", () => {
    // Catches: sign assumptions; [-5,-1] touches [-1,3] -> [-5,3].
    expect(mergeIntervals([[-5, -1], [-1, 3]])).toEqual([[-5, 3]]);
  });
});

describe("mergeIntervals — invalid input", () => {
  it("throws RangeError when a pair has start > end", () => {
    // Catches: missing validation letting [5,3] through as a real interval.
    expect(() => mergeIntervals([[5, 3]])).toThrow(RangeError);
  });

  it("does not throw for a valid zero-width pair (start === end)", () => {
    // Boundary just at the limit: start <= end must be permitted.
    // Catches: using `>=` in the guard and rejecting valid point intervals.
    expect(() => mergeIntervals([[4, 4]])).not.toThrow();
  });

  it("throws before returning any result when one pair is invalid", () => {
    // Catches: validating lazily and returning a partial merge for bad input.
    expect(() => mergeIntervals([[1, 2], [9, 4], [3, 5]])).toThrow(RangeError);
  });
});

describe("mergeIntervals — immutability", () => {
  it("does not mutate the input array", () => {
    // Catches: sorting in place, which would reorder the caller's array.
    const input = [[3, 6], [1, 4]];
    mergeIntervals(input);
    expect(input).toEqual([[3, 6], [1, 4]]);
  });

  it("does not mutate the inner pair arrays", () => {
    // Catches: writing last[1] = ... onto a shared reference from the input.
    const first = [1, 10];
    const second = [2, 5];
    mergeIntervals([first, second]);
    expect(first).toEqual([1, 10]);
    expect(second).toEqual([2, 5]);
  });

  it("returns pairs that are not the same references as the input pairs", () => {
    // Catches: aliasing so later mutation of the result corrupts the input.
    const input = [[1, 2]];
    const result = mergeIntervals(input);
    expect(result[0]).not.toBe(input[0]);
  });
});

